class HashTable {
  constructor(capacity=16) {
    this.cap=capacity; this.size=0;
    this.buckets=Array.from({length:capacity},()=>[]);
  }
  _hash(k) { return k % this.cap; }
  get(k) {
    for(const [bk,bv] of this.buckets[this._hash(k)]) if(bk===k) return bv;
    return -1;
  }
  put(k,v) {
    const b=this.buckets[this._hash(k)];
    for(const pair of b) if(pair[0]===k) { pair[1]=v; return; }
    b.push([k,v]); this.size++;
    if(this.size/this.cap>0.5) this._resize();
  }
  remove(k) {
    const b=this.buckets[this._hash(k)];
    const i=b.findIndex(p=>p[0]===k);
    if(i!==-1) { b.splice(i,1); this.size--; }
  }
  _resize() {
    const old=this.buckets; this.cap*=2; this.size=0;
    this.buckets=Array.from({length:this.cap},()=>[]);
    for(const b of old) for(const [k,v] of b) this.put(k,v);
  }
}
